Future<void> _handleEmailRegister(
  BuildContext context, {
  required _EmailRegisterInput input,
  String? nextRole,
}) async {
  UserCredential credential;
  try {
    credential = await _authCredentialGateway.createUserWithEmailAndPassword(
      email: input.email,
      password: input.password,
    );
  } on FirebaseAuthException catch (error) {
    if (!context.mounted) {
      return;
    }
    _showInfo(
      context,
      _resolveEmailRegisterFailureFeedbackMessageUseCase.execute(
        errorCode: error.code,
      ),
    );
    return;
  }

  try {
    final user = credential.user;
    final displayName = input.displayName?.trim();
    if (user != null && displayName != null && displayName.isNotEmpty) {
      await user.updateDisplayName(displayName);
    }
    await user?.sendEmailVerification();
  } catch (_) {
    if (!context.mounted) {
      return;
    }
